VALUES
  ('social-worker-moex-02091', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '威林斯基（Wilensky, 1964）提到專業化過程，是從給薪的專業人員開始、訓練學校興起、專業組織的形 成、爭取法律的保障與支持，最後才是訂定專業倫理守則來維持專業地位。請問，臺灣的第一個社會工 作專業組織名稱是？', '["臺灣社會工作專業人員協會", "中華民國醫務社會服務協會", "中華民國社會工作師公會全國聯合會", "臺灣社會工作實務發展協會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02092', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '民國105年6月6日頒布「協助積極自立脫離貧窮實施辦法」，鼓勵各地方政府辦理脫離貧困措施，請 問以下那個不是方法之一？', '["教育投資", "資產累積", "失業給付", "社會參與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02093', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者的自我覺察（self-awareness）是非常重要的，它關係到專業關係的建立，如果社會工作者的自 我覺察不足時，下列何者是偏差的？', '["產生反情感轉移而不自知", "依靠專業知識和技術就能勝任", "無法體會自身的缺點，連優點也被埋沒", "無法清楚的預估案主需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02094', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '任務中心和危機干預都是社會工作者常用的工作取向，下列何者是錯誤的描述？', '["確實有用，但其目的是有限的", "二者兼具理性或非理性的指導性和契約使用", "案主能在關係中容易掌握較大的權力", "是朝向更清楚、更集中焦點的工作取向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02095', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Hill（1993）提出的社會安全系統給付分成三大類，以下論述說明何者非其論點？', '["社會保險（contributory benefits）由被保險人、雇主與政府先繳保費，一定時間後與事故發生時方可申 請給付", "社會救助（social assistance）會評估給付者要經過資產調查，其資產和所得低於規定以下才給付", "社會津貼（social allowance）即只要國民遇到某種法定社會事故即可申請", "基礎年金（basic pension）屬社會津貼，非社會保險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02096', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '案主對於結案的負向反應，以下何者錯誤？', '["假裝還沒結束", "回復到早先行為狀態，或製造出新的問題", "和社工產生衝突，認為自己具備能力可以處理問題", "雙方關係凍結，不讓社工有離開或結束藉口"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02097', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '將問題解決模式應用在解決倫理兩難的議題上，是下列那位學者？', '["Lowenberg", "Holland", "Waggerman", "Reamer"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02098', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「社區工作」、「社區發展」和「社區組織」三者之間的關係，下列何者錯誤？', '["都是社會工作的方法，並無差異", "社區組織等同於社區工作", "社區發展等同於社區工作", "社區發展是發展中國家的自助行動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02099', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '村、里長與社區發展協會理事長之關係，以下敘述何者正確？', '["必須是同一人擔任", "兩者之產生其法令依據不同", "村里長做的事情社區發展協會不能介入", "社區發展協會服務的區域範圍比村里大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02100', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '優勢觀點為社會工作經常運用原則，請問以下敘述何者錯誤？', '["挑戰可能帶來威脅，但也可能是機會來源", "透過專業人員與案主共同合作，案主方能獲得最好的服務", "每個個人、團體和社區都有其優勢", "評量環境中的情境與個人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5823691fd765", "answer_pdf_sha1": "9eafd9800cdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
